const newArticleJson = JSON.parse($items("Generate Article (JSON)")[0].json.message.content);
const currentBlogsStr = $items("Get Existing Blogs (GitHub)")[0].json.content;
const currentBlogs = JSON.parse(currentBlogsStr);

// Add new article to the top of the array
currentBlogs.unshift(newArticleJson);

return [
  {
    json: {
      updatedArrayString: JSON.stringify(currentBlogs, null, 4),
      articleTitle: newArticleJson.es.title,
      url: `https://cablecore.es/es/blog/${newArticleJson.slug}`
    }
  }
];

